// GET /authorize - Authorization endpoint
app.get('/authorize', (req, res) => {
  const { response_type, client_id, redirect_uri, state, scope } = req.query;

  // Validate response_type
  if (response_type !== 'code') {
    return res.status(400).send(renderError('unsupported_response_type', 'Only authorization_code flow (response_type=code) is supported.'));
  }

  // Validate client
  const clientValidation = validateClient(client_id, redirect_uri);
  if (!clientValidation.valid) {
    return res.status(400).send(renderError(clientValidation.error, clientValidation.error_description));
  }

  // Store authorization request in session
  req.session.authRequest = {
    response_type,
    client_id,
    redirect_uri: redirect_uri || clientValidation.client.redirect_uris[0],
    state,
    scope: scope || 'openid profile email'
  };

  // If user is already logged in via SSO session, skip login form
  if (req.session.user) {
    return res.send(renderConsentPage(req.session.user, clientValidation.client, req.session.authRequest.scope));
  }

  // Show login form
  res.send(renderLoginPage(clientValidation.client.name));
});

// POST /authorize/login - Handle login form submission
app.post('/authorize/login', (req, res) => {
  const { username, password } = req.body;
  const authRequest = req.session.authRequest;

  if (!authRequest) {
    return res.status(400).send(renderError('invalid_request', 'No pending authorization request. Please start the flow again.'));
  }

  const user = users[username];
  if (!user || user.password !== password) {
    const client = registeredClients[authRequest.client_id];
    return res.send(renderLoginPage(client.name, 'Invalid username or password.'));
  }

  // Set SSO session
  req.session.user = { username: user.username, name: user.name, email: user.email, roles: user.roles };

  const client = registeredClients[authRequest.client_id];
  res.send(renderConsentPage(req.session.user, client, authRequest.scope));
});

// POST /authorize/consent - Handle consent decision
app.post('/authorize/consent', (req, res) => {
  const { decision } = req.body;
  const authRequest = req.session.authRequest;
  const user = req.session.user;

  if (!authRequest || !user) {
    return res.status(400).send(renderError('invalid_request', 'No pending authorization request or user session.'));
  }

  const redirect_uri = authRequest.redirect_uri;

  if (decision !== 'approve') {
    // User denied access
    const redirectUrl = new URL(redirect_uri);
    redirectUrl.searchParams.set('error', 'access_denied');
    redirectUrl.searchParams.set('error_description', 'User denied the authorization request');
    if (authRequest.state) redirectUrl.searchParams.set('state', authRequest.state);
    delete req.session.authRequest;
    return res.redirect(redirectUrl.toString());
  }

  // Generate authorization code
  const code = generateCode();
  authorizationCodes.set(code, {
    code,
    client_id: authRequest.client_id,
    redirect_uri: authRequest.redirect_uri,
    user: { username: user.username, name: user.name, email: user.email, roles: user.roles },
    scope: authRequest.scope,
    expires_at: Date.now() + 10 * 60 * 1000, // 10 minutes
    used: false
  });

  // Build redirect URL with code and state
  const redirectUrl = new URL(redirect_uri);
  redirectUrl.searchParams.set('code', code);
  if (authRequest.state) redirectUrl.searchParams.set('state', authRequest.state);

  delete req.session.authRequest;
  res.redirect(redirectUrl.toString());
});

// POST /token - Token endpoint
app.post('/token', (req, res) => {
  const { grant_type } = req.body;

  if (grant_type === 'authorization_code') {
    return handleAuthorizationCodeGrant(req, res);
  } else if (grant_type === 'refresh_token') {
    return handleRefreshTokenGrant(req, res);
  } else {
    return res.status(400).json({
      error: 'unsupported_grant_type',
      error_description: 'Supported grant types: authorization_code, refresh_token'
    });
  }
});

function handleAuthorizationCodeGrant(req, res) {
  const { code, redirect_uri, client_id, client_secret } = req.body;

  // Authenticate client
  let resolvedClientId = client_id;
  let resolvedClientSecret = client_secret;

  // Support HTTP Basic authentication for client credentials
  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.substring(6), 'base64').toString();
    const [basicId, basicSecret] = decoded.split(':');
    resolvedClientId = resolvedClientId || basicId;
    resolvedClientSecret = resolvedClientSecret || basicSecret;
  }

  if (!resolvedClientId || !resolvedClientSecret) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Client authentication required' });
  }

  if (!authenticateClient(resolvedClientId, resolvedClientSecret)) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Client authentication failed' });
  }

  if (!code) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing authorization code' });
  }

  const codeData = authorizationCodes.get(code);

  if (!codeData) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code not found' });
  }

  if (codeData.used) {
    // Code reuse detected - revoke all tokens issued with this code (security measure)
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code already used' });
  }

  if (codeData.expires_at < Date.now()) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code expired' });
  }

  if (codeData.client_id !== resolvedClientId) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Client ID mismatch' });
  }

  if (redirect_uri && codeData.redirect_uri !== redirect_uri) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'redirect_uri mismatch' });
  }

  // Mark code as used
  codeData.used = true;

  // Generate access token
  const access_token = generateToken();
  const accessTokenExpiry = Date.now() + 3600 * 1000; // 1 hour

  accessTokens.set(access_token, {
    access_token,
    token_type: 'Bearer',
    expires_at: accessTokenExpiry,
    client_id: resolvedClientId,
    user: codeData.user,
    scope: codeData.scope
  });

  // Generate refresh token
  const refresh_token = generateToken();
  refreshTokens.set(refresh_token, {
    refresh_token,
    client_id: resolvedClientId,
    user: codeData.user,
    scope: codeData.scope,
    expires_at: Date.now() + 30 * 24 * 3600 * 1000, // 30 days
    revoked: false
  });

  res.json({
    access_token,
    token_type: 'Bearer',
    expires_in: 3600,
    refresh_token,
    scope: codeData.scope
  });
}

function handleRefreshTokenGrant(req, res) {
  const { refresh_token, client_id, client_secret } = req.body;

  let resolvedClientId = client_id;
  let resolvedClientSecret = client_secret;

  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.substring(6), 'base64').toString();
    const [basicId, basicSecret] = decoded.split(':');
    resolvedClientId = resolvedClientId || basicId;
    resolvedClientSecret = resolvedClientSecret || basicSecret;
  }

  if (!resolvedClientId || !resolvedClientSecret) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Client authentication required' });
  }

  if (!authenticateClient(resolvedClientId, resolvedClientSecret)) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Client authentication failed' });
  }

  if (!refresh_token) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing refresh_token' });
  }

  const tokenData = refreshTokens.get(refresh_token);

  if (!tokenData || tokenData.revoked) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid or revoked refresh token' });
  }

  if (tokenData.expires_at < Date.now()) {
    refreshTokens.delete(refresh_token);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Refresh token expired' });
  }

  if (tokenData.client_id !== resolvedClientId) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Client ID mismatch' });
  }

  // Revoke old refresh token (rotation)
  tokenData.revoked = true;

  // Issue new access token
  const new_access_token = generateToken();
  accessTokens.set(new_access_token, {
    access_token: new_access_token,
    token_type: 'Bearer',
    expires_at: Date.now() + 3600 * 1000,
    client_id: resolvedClientId,
    user: tokenData.user,
    scope: tokenData.scope
  });

  // Issue new refresh token
  const new_refresh_token = generateToken();
  refreshTokens.set(new_refresh_token, {
    refresh_token: new_refresh_token,
    client_id: resolvedClientId,
    user: tokenData.user,
    scope: tokenData.scope,
    expires_at: Date.now() + 30 * 24 * 3600 * 1000,
    revoked: false
  });

  res.json({
    access_token: new_access_token,
    token_type: 'Bearer',
    expires_in: 3600,
    refresh_token: new_refresh_token,
    scope: tokenData.scope
  });
}

// POST /revoke - Token revocation endpoint
app.post('/revoke', (req, res) => {
  const { token, token_type_hint, client_id, client_secret } = req.body;

  let resolvedClientId = client_id;
  let resolvedClientSecret = client_secret;

  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.substring(6), 'base64').toString();
    const [basicId, basicSecret] = decoded.split(':');
    resolvedClientId = resolvedClientId || basicId;
    resolvedClientSecret = resolvedClientSecret || basicSecret;
  }

  if (!authenticateClient(resolvedClientId, resolvedClientSecret)) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  if (!token) {
    return res.status(400).json({ error: 'invalid_request' });
  }

  // Try to revoke as access token
  if (accessTokens.has(token)) {
    const tokenData = accessTokens.get(token);
    if (tokenData.client_id === resolvedClientId) {
      accessTokens.delete(token);
    }
  }

  // Try to revoke as refresh token
  if (refreshTokens.has(token)) {
    const tokenData = refreshTokens.get(token);
    if (tokenData.client_id === resolvedClientId) {
      tokenData.revoked = true;
    }
  }

  // Always return 200 per RFC 7009
  res.status(200).json({});
});

// GET /userinfo - UserInfo endpoint (protected)
app.get('/userinfo', requireBearerToken, (req, res) => {
  const { user, scope } = req.tokenData;
  const scopes = scope.split(' ');

  const response = { sub: user.username };

  if (scopes.includes('profile')) {
    response.name = user.name;
    response.preferred_username = user.username;
    response.roles = user.roles;
  }

  if (scopes.includes('email')) {
    response.email = user.email;
    response.email_verified = true;
  }

  res.json(response);
});

// GET /introspect - Token introspection endpoint
app.post('/introspect', (req, res) => {
  const { token, client_id, client_secret } = req.body;

  let resolvedClientId = client_id;
  let resolvedClientSecret = client_secret;

  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.substring(6), 'base64').toString();
    const [basicId, basicSecret] = decoded.split(':');
    resolvedClientId = resolvedClientId || basicId;
    resolvedClientSecret = resolvedClientSecret || basicSecret;
  }

  if (!authenticateClient(resolvedClientId, resolvedClientSecret)) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  const tokenData = accessTokens.get(token);

  if (!tokenData || tokenData.expires_at < Date.now()) {
    return res.json({ active: false });
  }

  res.json({
    active: true,
    scope: tokenData.scope,
    client_id: tokenData.client_id,
    username: tokenData.user.username,
    token_type: tokenData.token_type,
    exp: Math.floor(tokenData.expires_at / 1000),
    iat: Math.floor((tokenData.expires_at - 3600 * 1000) / 1000),
    sub: tokenData.user.username,
    name: tokenData.user.name,
    email: tokenData.user.email
  });
});

