app.listen(PORT, () => {
  console.log(`\n🔐 OAuth 2.0 Authorization Server running on http://localhost:${PORT}`);
  console.log(`   Server metadata: http://localhost:${PORT}/.well-known/oauth-authorization-server`);
  console.log(`\n   Example authorization URL:`);
  console.log(`   http://localhost:${PORT}/authorize?response_type=code&client_id=webapp-portal&redirect_uri=http://localhost:4001/callback&state=random123&scope=openid%20profile%20email\n`);
});

module.exports = app;